void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.95; //or try: ret -= 0.004;
ret = tex2d(sampler_rand00,vUvOriginal);

  fragColor = ret;
